customCss:
/* __site_font_upload_start__ */
@font-face {
  font-family: "Co";
  src: url("../../fonts/Co/Co-Headline-Light.otf") format("opentype");
  font-style: normal;
  font-weight: 300;
  font-display: swap;
}

@font-face {
  font-family: "Co";
  src: url("../../fonts/Co/Co-Headline.otf") format("opentype");
  font-style: normal;
  font-weight: 400;
  font-display: swap;
}

@font-face {
  font-family: "Co";
  src: url("../../fonts/Co/Co-Headline-Bold.otf") format("opentype");
  font-style: normal;
  font-weight: 700;
  font-display: swap;
}

/* __site_font_upload_end__ */

containerScss:
.container {
  position: relative;
  width: 100%;
  padding: 0 15px;
  margin: 0 auto;
  z-index: 1;

  @media (min-width: 48px) {
    //768px
    max-width: 100rem;
  }

  @media (min-width: 62rem) {
    //992px
    max-width: 110rem;
  }

  @media (min-width: 75rem) {
    //1200px
    max-width: 130rem;
  }

  @media (min-width: 87.5rem) {
    //1400px
    max-width: 129rem;
  }
  @media (min-width: 93.75rem) {
    //1500px
    max-width: 140rem;
  }
  @media (min-width: 100rem) {
    //1600px
    max-width: 150rem;
  }
  @media (min-width: 106.25rem) {
    //1700px
    max-width: 166.8rem;
  }
}
